33	int PluginCommand::main(int argc, char* const argv[]) {
34	    int need_unload = false;
35	    int need_reload = false;
36	    int opt;
37	    int option_index = 0;
38	    optind = 0; // reset
39	    static struct option long_options[] = {
40	        {"unload",  no_argument,       0, 'u'},
41	        {"reload",  no_argument,       0, 'r'},
42	        {0,         0,                 0,  0 },
43	    };
44	
45	    while ((opt = getopt_long(argc, argv, "ur",
46	                long_options, &option_index)) != -1) {
47	        switch (opt) {
48	            case 'u':
49	                // need_unload = true;
50	                break;
51	            case 'r':
52	                // need_reload = true;
53	                break;
54	        }
55	    }
56	
57	    if (optind >= argc) {
58	        ShowEnv();
59	        return 0;
60	    }
61	
62	    if (need_unload) {
63	        return UnLoad(argv[optind]);
64	    } else {
65	        return Load(argv[optind], need_reload);
66	    }
67	    return 0;
68	}
