70	int PluginCommand::UnLoad(const char* path) {
71	    auto it = std::remove_if(plugins.begin(), plugins.end(),
72	        [&](const std::unique_ptr<Plugin>& plugin) {
73	            return plugin->Path() == path;
74	        }
75	    );
76	    if (it != plugins.end()) {
77	        Plugin* plugin = it->get();
78	        Command* command = plugin->Cmd();
79	        void* handle = plugin->Handle();
80	        plugins.erase(it);
81	        if (command) CommandManager::PopExtendCommand(command);
82	        // if (handle) dlclose(handle);
83	    }
84	    return 0;
85	}
