87	int PluginCommand::Load(const char* path, bool flag) {
88	    if (flag) UnLoad(path);
89	
90	    std::unique_ptr<Plugin> plugin = std::make_unique<Plugin>(path, nullptr);
91	    current_plugin = plugin.get();
92	    void* handle = dlopen(path, RTLD_NOW);
93	    // do plugin constructor
94	    if (plugin->Cmd() && handle) {
95	        LOGI("Linker env...\n");
96	        plugin->HookHandle(handle);
97	        plugins.push_back(std::move(plugin));
98	        current_plugin = nullptr;
99	        LOGI("env new command \"%s\"\n", plugins[plugins.size() - 1]->Cmd()->get().c_str());
100	    } else {
101	        if (!handle) LOGE("dlopen %s fail!\n", path);
102	    }
103	
104	    return 0;
105	}
