### Writing Custom Plugins

#### **Minimal Plugin Template**

```cpp
#include "logger/log.h"
#include "command/command.h"
#include "command/command_manager.h"

class MyPlugin : public Command {
public:
    MyPlugin() : Command("myplugin") {}

    int prepare(int argc, char* const argv[]) override {
        return Command::ONCHLD;  // or CONTINUE/FINISH
    }

    int main(int argc, char* const argv[]) override {
        LOGI("My custom analysis logic!\n");

        // Parse arguments with getopt
        // Access core APIs
        // Perform analysis

        return 0;
    }

    void usage() override {
        LOGI("Usage: myplugin [options]\n");
        LOGI("  -x, --example    Example option\n");
    }
};

// Auto-registration via constructor attribute
void __attribute__((constructor)) myplugin_init(void) {
    CommandManager::PushExtendCommand(new MyPlugin());
}

void __attribute__((destructor)) myplugin_fini(void) {
    // Cleanup if needed
}
```

#### **Build Configuration**

```bash
# Compile as shared library
g++ -shared -fPIC -std=gnu++17 \
    -I/path/to/OpenCoreAnalysisKit/parser \
    -I/path/to/OpenCoreAnalysisKit/android \
    myplugin.cpp -o plugin-myplugin.so

# Load in core-parser
core-parser -c core.dump
core-parser> plugin plugin-myplugin.so
Linker env...
env new command "myplugin"
core-parser> myplugin
My custom analysis logic!
```

